public class Solution {
    public static void main(String[] args) {
        int result = reverseNum(1234);
        System.out.println(result);
    }

    public static int reverseNum(int n) {
        int reversed = 0;

        while (n != 0) {
            int digit = n % 10;
            reversed = reversed * 10 + digit;
            n /= 10;
        }

        return reversed;
    }
}
